def find_free_slots(meetings, work_start, work_end):
    # Clip meetings to the working window
    clipped = []
    for s, e in meetings:
        cs = max(s, work_start)
        ce = min(e, work_end)
        if cs < ce:
            clipped.append([cs, ce])

    if not clipped:
        return [[work_start, work_end]]

    clipped.sort()

    # Merge overlapping/adjacent intervals
    merged = [clipped[0][:]]
    for s, e in clipped[1:]:
        if s <= merged[-1][1]:
            merged[-1][1] = max(merged[-1][1], e)
        else:
            merged.append([s, e])

    # Find free slots in gaps
    free = []
    prev_end = work_start
    for s, e in merged:
        if prev_end < s:
            free.append([prev_end, s])
        prev_end = max(prev_end, e)
    if prev_end < work_end:
        free.append([prev_end, work_end])

    return free

