import unittest

class TestSolution(unittest.TestCase):
    def test_basic_two_meetings(self):
        result = find_free_slots([[540, 600], [630, 700]], 480, 1020)
        self.assertEqual(result, [[480, 540], [600, 630], [700, 1020]])

    def test_overlapping_meetings(self):
        result = find_free_slots([[540, 660], [600, 720]], 480, 1020)
        self.assertEqual(result, [[480, 540], [720, 1020]])

    def test_no_meetings(self):
        result = find_free_slots([], 480, 1020)
        self.assertEqual(result, [[480, 1020]])

    def test_hidden_full_day_meeting(self):
        result = find_free_slots([[480, 1020]], 480, 1020)
        self.assertEqual(result, [])

    def test_hidden_meetings_outside_window(self):
        result = find_free_slots([[300, 400], [1100, 1200]], 480, 1020)
        self.assertEqual(result, [[480, 1020]])

    def test_hidden_adjacent_meetings(self):
        result = find_free_slots([[540, 600], [600, 660]], 480, 1020)
        self.assertEqual(result, [[480, 540], [660, 1020]])

    def test_hidden_meeting_at_window_start(self):
        result = find_free_slots([[480, 600]], 480, 1020)
        self.assertEqual(result, [[600, 1020]])

    def test_hidden_many_overlapping(self):
        result = find_free_slots([[500, 550], [520, 600], [590, 700], [800, 900]], 480, 1020)
        self.assertEqual(result, [[480, 500], [700, 800], [900, 1020]])

    def test_hidden_meeting_partially_outside(self):
        result = find_free_slots([[400, 540], [950, 1100]], 480, 1020)
        self.assertEqual(result, [[540, 950]])

    def test_hidden_unsorted_meetings(self):
        result = find_free_slots([[700, 800], [500, 550], [600, 650]], 480, 900)
        self.assertEqual(result, [[480, 500], [550, 600], [650, 700], [800, 900]])

    def test_hidden_single_minute_gap(self):
        result = find_free_slots([[480, 599], [600, 1020]], 480, 1020)
        self.assertEqual(result, [[599, 600]])

if __name__ == '__main__':
    unittest.main()
